// settings.gradle.kts

// Имя корневого проекта
rootProject.name = "my-project"

// Для многомодульного проекта:
// include("app")
// include("core")
// include("data")

// build.gradle.kts

plugins {
    java                          // Плагин для компиляции Java
    application                   // Плагин для запуска приложения
}

repositories {
    mavenCentral()                // Где искать зависимости
}

dependencies {
    implementation("com.google.guava:guava:33.0.0-jre") // Основная зависимость
    testImplementation("org.junit.jupiter:junit-jupiter:5.10.2") // Тестовая
}

application {
    mainClass.set("com.example.App") // Главный класс (ваш Java-класс с main)
}

tasks.test {
    useJUnitPlatform()            // Обязательно для JUnit 5
}

// build.gradle.kts

// Простая задача
tasks.register("hello") {
    group = "custom"             // Группа в ./gradlew tasks
    description = "Prints hello" // Описание

    doLast {
        println("Hello, Gradle!")
    }
}

// Задача с зависимостью
tasks.register("greet") {
    dependsOn("hello")  // Сначала выполнится hello
    doLast {
        println("How are you?")
    }
}

tasks.register("demo") {
    // Это выполняется в фазе КОНФИГУРАЦИИ (всегда!)
    println("Configuring demo task")

    doFirst {
        // Выполняется ПЕРЕД основными действиями задачи
        println("Before action")
    }

    doLast {
        // Выполняется ПОСЛЕ основных действий задачи
        println("After action")
    }
}

// Задача копирования файлов
tasks.register<Copy>("copyDocs") {
    from("src/docs")
    into("build/docs")
    include("**/*.md")
}

// Задача удаления
tasks.register<Delete>("cleanLogs") {
    delete("logs/")
}

// Задача архивирования
tasks.register<Zip>("zipSources") {
    from("src/")
    archiveFileName.set("sources.zip")
    destinationDirectory.set(layout.buildDirectory.dir("archives"))
}

// build.gradle.kts

repositories {
    mavenCentral()    // Главный публичный репозиторий
    google()          // Для Android-библиотек
    mavenLocal()      // Локальный кэш ~/.m2/repository

    // Кастомный репозиторий
    maven {
        url = uri("https://repo.mycompany.com/maven")
        credentials {
            username = project.findProperty("repoUser") as String? ?: ""
            password = project.findProperty("repoPass") as String? ?: ""
        }
    }
}

dependencies {
    //       group               artifact    version
    //       ↓                   ↓           ↓
    implementation("com.google.guava:guava:33.0.0-jre")
    implementation("org.apache.commons:commons-lang3:3.14.0")
    implementation("com.fasterxml.jackson.core:jackson-databind:2.17.0")
}

// Модуль :core
plugins {
    `java-library`  // Нужен для 'api'
}

dependencies {
    api("com.google.guava:guava:33.0.0-jre")
    // ↑ Guava видна ВСЕМ, кто зависит от :core

    implementation("org.slf4j:slf4j-api:2.0.12")
    // ↑ SLF4J видна ТОЛЬКО внутри :core
}

// Модуль :app
dependencies {
    implementation(project(":core"))
    // :app может использовать Guava (api)
    // :app НЕ может использовать SLF4J (implementation)
}

// Принудительная версия зависимости
configurations.all {
    resolutionStrategy {
        force("com.google.guava:guava:33.0.0-jre")
    }
}

// Исключение транзитивной зависимости
dependencies {
    implementation("org.some:library:1.0") {
        exclude(group = "org.unwanted", module = "module")
    }
}

# gradle/libs.versions.toml

[versions]
guava = "33.0.0-jre"
junit = "5.10.2"
jackson = "2.17.0"

[libraries]
guava = { module = "com.google.guava:guava", version.ref = "guava" }
junit-jupiter = { module = "org.junit.jupiter:junit-jupiter", version.ref = "junit" }
jackson-databind = { module = "com.fasterxml.jackson.core:jackson-databind", version.ref = "jackson" }

[plugins]
spring-boot = { id = "org.springframework.boot", version = "3.2.4" }

// build.gradle.kts — использование каталога
dependencies {
    implementation(libs.guava)
    implementation(libs.jackson.databind)
    testImplementation(libs.junit.jupiter)
}

plugins {
    java                              // Core-плагин (встроен в Gradle)
    application                       // Core-плагин
    id("org.springframework.boot") version "3.2.4"  // Community-плагин
    kotlin("jvm") version "2.0.0"     // Kotlin-плагин
}

plugins {
    java
}

java {
    sourceCompatibility = JavaVersion.VERSION_21
    targetCompatibility = JavaVersion.VERSION_21

    toolchain {
        languageVersion.set(JavaLanguageVersion.of(21))
    }
}

// Настройка компилятора
tasks.withType<JavaCompile> {
    options.encoding = "UTF-8"
    options.compilerArgs.addAll(listOf("-Xlint:all", "-Werror"))
}

plugins {
    application
}

application {
    mainClass.set("com.example.App")

    // Аргументы JVM
    applicationDefaultJvmArgs = listOf("-Xmx512m", "-Denv=dev")
}

// Теперь доступны задачи:
// ./gradlew run              — запуск приложения
// ./gradlew installDist      — установка в build/install/
// ./gradlew distZip          — ZIP-архив дистрибутива
// ./gradlew distTar          — TAR-архив дистрибутива

dependencies {
    testImplementation("org.junit.jupiter:junit-jupiter:5.10.2")
    testImplementation("org.assertj:assertj-core:3.25.3")  // Удобные assert'ы
    testImplementation("org.mockito:mockito-core:5.11.0")   // Моки
}

tasks.test {
    useJUnitPlatform()  // Обязательно для JUnit 5!

    // Настройки вывода
    testLogging {
        events("passed", "skipped", "failed")
        showExceptions = true
        showCauses = true
        showStackTraces = true
        exceptionFormat = org.gradle.api.tasks.testing.logging.TestExceptionFormat.FULL
    }

    // Запуск тестов параллельно
    maxParallelForks = Runtime.getRuntime().availableProcessors() / 2
}

plugins {
    java
    jacoco  // Плагин покрытия кода
}

jacoco {
    toolVersion = "0.8.11"
}

tasks.test {
    useJUnitPlatform()
    finalizedBy(tasks.jacocoTestReport)  // Отчёт после тестов
}

tasks.jacocoTestReport {
    dependsOn(tasks.test)
    reports {
        xml.required.set(true)       // Для CI/CD
        html.required.set(true)      // Для человека
        csv.required.set(false)
    }
}

// Проверка минимального покрытия
tasks.jacocoTestCoverageVerification {
    violationRules {
        rule {
            limit {
                minimum = "0.80".toBigDecimal()  // Минимум 80%
            }
        }
    }
}

plugins {
    java
    checkstyle  // Подключаем Checkstyle
}

checkstyle {
    toolVersion = "10.14.2"
    configFile = file("config/checkstyle/checkstyle.xml")
    isIgnoreFailures = false   // Ломать сборку при нарушениях
    maxWarnings = 0            // Никаких предупреждений!
}

plugins {
