    pmd       // Статический анализ паттернов
}

pmd {
    toolVersion = "7.0.0"
    isConsoleOutput = true
    rulesets = listOf(
        "category/java/bestpractices.xml",
        "category/java/errorprone.xml",
        "category/java/codestyle.xml"
    )
}

plugins {
